class Solution {
    public boolean backspaceCompare(String s, String t) {
        int m = s.length();
        int n = t.length();

        for (int i = 0; i < m; i++) {
            if (s.charAt(i) == '#' && t.charAt(i) != '#') {
                return false;
            }
        }

        for (int i = 0; i < n; i++) {
            if (s.charAt(m - i - 1) != t.charAt(n - i - 1)) {
                return false;
            }
        }

        return true;
    }
}
```

